// supplier-dashboard.component.ts
import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { SupplierAuthService, SupplierIngredient } from '../../../services/supplier-auth.service';
import { SupplierProductsService } from '../../../services/supplier-products.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-supplier-dashboard',
  standalone: true,
  imports: [CommonModule, LucideAngularModule],
  templateUrl: './supplier-dashboard.html'
})
export class SupplierDashboard implements OnInit {
  private supplierAuthService = inject(SupplierAuthService);
  private supplierProductsService = inject(SupplierProductsService);

  supplierProfile: any = null;
  ingredients: SupplierIngredient[] = [];
  restaurants: any[] = [];
  products: any[] = [];
  isLoading = true;

  async ngOnInit() {
    await this.loadData();
  }

  async loadData() {
    this.isLoading = true;
    
    try {
      // Carica profilo fornitore
      await this.supplierAuthService.loadSupplierProfile();
      this.supplierAuthService.supplierProfile$.subscribe(profile => {
        this.supplierProfile = profile;
      });

      // Carica ingredienti forniti
      this.ingredients = await this.supplierAuthService.getSupplierIngredients();

      // Carica ristoranti clienti
      this.restaurants = await this.supplierAuthService.getSupplierRestaurants();

      // Carica prodotti fornitore
      await this.supplierProductsService.loadSupplierProducts();
      this.supplierProductsService.products$.subscribe(products => {
        this.products = products;
      });

    } catch (error) {
      console.error('Error loading supplier data:', error);
    } finally {
      this.isLoading = false;
    }
  }

  get totalRestaurants(): number {
    return this.restaurants.length;
  }

  get totalIngredients(): number {
    return this.ingredients.length;
  }

  get totalProducts(): number {
    return this.products.length;
  }

  get activeProducts(): number {
    return this.products.filter(p => p.is_available).length;
  }
}